+        processNewTask = headInnerIdx == PING_PONG_STAGES - 1;
+        if (processNewTask) {
+            taskIdx += PING_PONG_STAGES * cubeCoreNum;
+        }
+        
+        currStage = (currStage + 1) % PING_PONG_STAGES;
+    }
+
+
