+                    blockMmadWH(tensorBlockW, tensorBlockH, tensorBlockV, cube1Shape);
+                    blockMmadWH.finalWaitFlags();
+                }
+                Arch::CrossCoreSetFlag<0x2, PIPE_FIX>(cubeBlockScheduler.cube1Done);
+
